package webadmin

import "html/template"

var cleanLoginTemplate = template.Must(template.New("clean_login").Parse(`<!doctype html>
<html><head><meta charset="utf-8"><title>Robot Login</title><style>
body{font-family:system-ui,-apple-system,Segoe UI,Arial,sans-serif;background:#eef2f6;color:#17202a;margin:0;display:grid;place-items:center;min-height:100vh}
form{width:320px;background:#fff;border:1px solid #d7dee8;border-radius:8px;padding:22px;box-shadow:0 16px 45px rgba(15,23,42,.12)}
h1{font-size:18px;margin:0 0 16px}label{display:block;font-size:13px;color:#64748b;margin-bottom:6px}input{width:100%;box-sizing:border-box;height:36px;border:1px solid #b8c2d0;border-radius:6px;padding:0 10px;font:inherit}button{width:100%;height:36px;margin-top:14px;border:0;border-radius:6px;background:#2563eb;color:white;font:inherit;cursor:pointer}.err{margin-top:10px;color:#b91c1c;font-size:13px}
</style></head><body><form method="post" action="/login"><h1>Robot Web</h1><label>Password</label><input name="password" type="password" autofocus><button>Login</button>{{if .Error}}<div class="err">{{.Error}}</div>{{end}}</form></body></html>`))

var cleanIndexTemplate = template.Must(template.New("clean_index").Parse(`<!doctype html>
<html><head><meta charset="utf-8"><title>TW Robot Web</title><style>
:root{--bg:#eef2f6;--panel:#fff;--line:#d7dee8;--soft:#f8fafc;--text:#17202a;--muted:#64748b;--blue:#2563eb;--green:#15803d;--red:#b91c1c;--amber:#a16207}
*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:14px system-ui,-apple-system,Segoe UI,Arial,sans-serif}header{height:48px;display:flex;align-items:center;gap:16px;padding:0 16px;background:#17202a;color:#fff}header b{font-size:16px}header span{opacity:.85}header a{margin-left:auto;color:#fff;text-decoration:none}.wrap{padding:12px 14px}.cards{display:grid;grid-template-columns:repeat(8,minmax(120px,1fr));gap:8px;margin-bottom:10px}.card,.scheduler,.panel{background:var(--panel);border:1px solid var(--line);border-radius:8px}.card{padding:9px 10px}.k{font-size:12px;color:var(--muted)}.v{font-size:18px;font-weight:700;margin-top:3px}.good .v{color:var(--green)}.bad .v{color:var(--red)}.service-lights{display:flex;gap:8px;align-items:center;flex-wrap:wrap;font-size:12px;font-weight:600;line-height:1.35}.svc{display:inline-flex;align-items:center;gap:4px;color:#334155}.dot{width:9px;height:9px;border-radius:50%;background:#94a3b8}.dot.open{background:var(--green)}.dot.closed{background:var(--red)}.toolbar{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:10px}.toolbar .spacer{flex:1}button{height:32px;border:1px solid #b8c2d0;border-radius:6px;background:#fff;color:var(--text);padding:0 11px;font:inherit;cursor:pointer}button:hover{background:#f8fafc}button:disabled{opacity:.55;cursor:not-allowed}.primary{background:var(--blue);border-color:var(--blue);color:#fff}.primary:hover{background:var(--blue);border-color:var(--blue);color:#fff}.danger{border-color:#efb5b5;color:var(--red)}input,textarea{font:inherit;border:1px solid #b8c2d0;border-radius:6px;padding:7px;background:#fff}input[type=number]{width:92px}.scheduler{padding:10px;margin-bottom:10px}.schedgrid{display:grid;grid-template-columns:repeat(6,minmax(120px,1fr));gap:8px}.scheditem{border:1px solid #edf1f5;border-radius:6px;padding:7px 8px;background:#fbfdff}.schedreason{margin-top:8px;color:var(--muted);font-size:12px}.grid{display:grid;grid-template-rows:minmax(420px,1fr);height:calc(100vh - 150px)}.panel{overflow:hidden}.panelhead{height:36px;display:flex;align-items:center;gap:10px;padding:0 10px;background:var(--soft);border-bottom:1px solid var(--line)}.panelhead h3{margin:0;font-size:14px}.panelhead span{color:var(--muted);font-size:12px}.tablebox{height:calc(100% - 36px);overflow:auto}table{width:100%;border-collapse:collapse}th,td{padding:7px 8px;border-bottom:1px solid #edf1f5;text-align:center;white-space:nowrap}th{background:var(--soft);position:sticky;top:0;z-index:2;color:#475569;font-size:12px}tbody tr:nth-child(even){background:#fbfdff}tbody tr:hover{background:#eff6ff}tr.sel,.bulk-selected tr{background:#dbeafe!important}.pill{display:inline-block;padding:2px 7px;border-radius:999px;background:#e2e8f0;color:#334155;font-size:12px}.pill.ok{background:#dcfce7;color:#166534}.pill.warn{background:#fef3c7;color:#92400e}.toast{position:fixed;right:14px;bottom:14px;max-width:520px;background:#17202a;color:#fff;border-radius:7px;padding:10px 12px;box-shadow:0 12px 32px rgba(15,23,42,.22);display:none}dialog{border:1px solid var(--line);border-radius:8px;padding:0;min-width:460px;max-width:min(920px,96vw);box-shadow:0 18px 70px rgba(15,23,42,.22)}dialog::backdrop{background:rgba(15,23,42,.32)}.dlghead,.dlgfoot{display:flex;align-items:center;padding:12px 14px;background:var(--soft);border-bottom:1px solid var(--line)}.dlghead h3{margin:0;font-size:15px}.dlghead button{margin-left:auto}.dlgbody{padding:14px}.dlgfoot{justify-content:flex-end;gap:8px;border-top:1px solid var(--line);border-bottom:0}.formgrid{display:grid;grid-template-columns:160px 1fr;gap:10px 12px;align-items:center}.muted{color:var(--muted)}.configbox{width:min(860px,88vw);height:min(560px,70vh);font:12px/1.45 Consolas,monospace}@media(max-width:1250px){.cards{grid-template-columns:repeat(4,1fr)}}@media(max-width:900px){.cards,.schedgrid{grid-template-columns:repeat(2,1fr)}.grid{height:auto;grid-template-rows:420px}}
</style></head><body>
<header><b>TW Robot Web</b><span>Web {{.WebAddr}}</span><span>TCP {{.RobotAddr}}</span><span id="gameHead">Game: -</span><span id="robotUptimeHead">Runtime -</span><a href="/logout">Logout</a></header>
<div class="wrap">
<div class="cards"><div class="card" id="mRobot"><div class="k">Robot</div><div class="v">-</div></div><div class="card" id="mGame"><div class="k">Game port</div><div class="v">-</div></div><div class="card" id="mMonitor"><div class="k">Services</div><div class="v service-lights">-</div></div><div class="card" id="mDB"><div class="k">Database</div><div class="v">-</div></div><div class="card" id="mKey"><div class="k">Key</div><div class="v">-</div></div><div class="card"><div class="k">Auto</div><div class="v" id="mAuto">-</div></div><div class="card" id="mOnlineCard"><div class="k" id="mOnlineLabel">Online / Target</div><div class="v" id="mOnline">-</div></div><div class="card"><div class="k">Store</div><div class="v" id="mStore">-</div></div></div>
<div class="toolbar"><button class="primary" onclick="refreshAll()">Refresh</button><button data-key-action="1" onclick="openAutoDialog()">Auto</button><button data-key-action="1" onclick="openOnlineDialog()">Online</button><button data-key-action="1" onclick="runAction('robotsMove')">Move</button><button data-key-action="1" onclick="runAction('robotsShout')">Shout</button><button data-key-action="1" onclick="runAction('robotsStoreAsync')">Store</button><button data-key-action="1" onclick="runAction('robotsLogoutAsync')">Logout</button><button id="cleanupButton" class="danger" onclick="openCleanupDialog()">Cleanup</button><button id="restartRobotButton" class="danger" onclick="restartRobot()">Restart Robot</button><button id="keyButton" onclick="openKeyDialog()">Key</button><button id="maxButton" onclick="openMaxDialog()">Max</button><button id="scriptButton" onclick="openScriptDialog()">Script</button><button id="marketButton" onclick="openMarketDialog()">Market</button><button id="partyCompatButton" onclick="openPartyCompatDialog()">Party</button><span class="spacer"></span><label><select id="autoRefreshInterval" onchange="toggleAutoRefresh()"><option value="3000">3s</option><option value="5000">5s</option><option value="8000" selected>8s</option><option value="off">Off</option></select> Auto refresh</label><label>Count <input id="actionCount" type="number" min="1" max="1000" value="1"></label><span class="muted" id="selectedInfo">Selected 0</span></div>
<div class="scheduler"><div class="schedgrid"><div class="scheditem"><div class="k">Policy mode</div><div class="v" id="sMode">-</div></div><div class="scheditem"><div class="k">Attach pace</div><div class="v" id="sOnline">-</div></div><div class="scheditem"><div class="k">Store policy</div><div class="v" id="sStore">-</div></div><div class="scheditem"><div class="k">Scale window</div><div class="v" id="sScale">-</div></div><div class="scheditem"><div class="k">Pressure guard</div><div class="v" id="sPressure">-</div></div><div class="scheditem"><div class="k">Release guard</div><div class="v" id="sRelease">-</div></div></div><div class="schedreason" id="sReason">-</div></div>
<div class="grid"><div class="panel"><div class="panelhead"><h3>Robots</h3><span id="listInfo">-</span></div><div class="tablebox"><table id="tbl"><thead><tr><th><input type="checkbox" id="checkAll" onchange="toggleAll(this.checked)"></th><th>UID</th><th>CID</th><th>Name</th><th>Actor</th><th>State</th><th>Level</th><th>Job</th><th>Town</th><th>Area</th><th>X</th><th>Y</th><th>Uptime</th><th>Store</th></tr></thead><tbody></tbody></table></div></div></div></div>
<dialog id="modal"><div class="dlghead"><h3 id="modalTitle"></h3><button onclick="closeModal()">Close</button></div><div class="dlgbody" id="modalBody"></div><div class="dlgfoot" id="modalFoot"></div></dialog><div class="toast" id="toast"></div>
<script>
const selected=new Set();let currentRows=[],busy=false,keyBlocked=false,dbBlocked=false,gameBlocked=false,autoRefreshTimer=null,gameMaxUser=0,lastRobotsRefresh=0;const robotsRefreshMs=30000;
function byId(id){return document.getElementById(id)}function text(v){return String(v??'')}function escapeHTML(v){return text(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function toast(msg){const t=byId('toast');t.textContent=msg;t.style.display='block';clearTimeout(t._timer);t._timer=setTimeout(()=>t.style.display='none',3600)}
function actionName(cmd){return ({robotsOnlineAsync:'Online',robotsStoreAsync:'Store',robotsLogoutAsync:'Logout',cleanupRobotsAsync:'Cleanup',robotsMove:'Move',robotsShout:'Shout'}[cmd]||cmd)}
function jobGrowName(job,grow){const names={0:{0:'鬼剑士',1:'剑魂',2:'鬼泣',3:'狂战士',4:'阿修罗'},1:{0:'格斗家',1:'气功师',2:'散打',3:'街霸',4:'柔道家'},2:{0:'神枪手',1:'漫游枪手',2:'枪炮师',3:'机械师',4:'弹药专家'},3:{0:'魔法师',1:'元素师',2:'召唤师',3:'战斗法师',4:'魔道学者'},4:{0:'圣职者',1:'圣骑士',2:'蓝拳圣使',3:'驱魔师',4:'复仇者'},5:{0:'女神枪手',1:'漫游枪手',2:'枪炮师',3:'机械师',4:'弹药专家'},6:{0:'暗夜使者',1:'刺客',2:'死灵术士'},7:{0:'女格斗家',1:'气功师',2:'散打',3:'街霸',4:'柔道家'},8:{0:'女魔法师',1:'元素师',2:'召唤师',3:'战斗法师',4:'魔道学者'},9:{0:'黑暗武士'},10:{0:'缔造者'}};return (names[job]&&names[job][grow])||((names[job]&&names[job][0])?names[job][0]+' '+text(grow):text(job)+'/'+text(grow))}
function villageDisplay(a){return a.village_name||text(a.village)}
function setBusy(v){busy=v;document.querySelectorAll('button').forEach(b=>b.disabled=v);applyKeyGate()}function applyKeyGate(){const blocked=keyBlocked||dbBlocked||gameBlocked;document.querySelectorAll('[data-key-action="1"]').forEach(b=>b.disabled=busy||blocked);const kb=byId('keyButton');if(kb)kb.disabled=busy;const cb=byId('cleanupButton');if(cb)cb.disabled=busy}
async function api(command,payload={}){const r=await fetch('/api/call',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({command,payload})});const x=await r.json().catch(()=>({ok:false,error:'invalid json'}));if(!r.ok||!x.ok)throw new Error(x.error||('HTTP '+r.status));return x}
function resultOf(x){return x&&x.result&&x.result.result?x.result.result:x.result}function writeLog(v){try{console.log(v)}catch(e){}}
async function guarded(name,fn){if(busy)return;setBusy(true);try{const out=await fn();if(out!==undefined)writeLog(out);toast(name+' ok')}catch(e){writeLog({ok:false,error:e.message});toast(name+' failed: '+e.message)}finally{setBusy(false)}}
async function refreshAll(){await guarded('Refresh',async()=>{await Promise.all([refreshStatus(),refreshScheduler(),refreshRobots(),checkGame(),checkServices(),refreshDatabase(),refreshKeypair()]);return 'refreshed '+new Date().toLocaleTimeString()})}
async function refreshQuiet(){if(busy||document.hidden||byId('autoRefreshInterval')?.value==='off')return;try{const tasks=[refreshStatus(),refreshScheduler(),checkGame(),checkServices(),refreshDatabase(),refreshKeypair()];if(Date.now()-lastRobotsRefresh>=robotsRefreshMs)tasks.push(refreshRobots());await Promise.all(tasks)}catch(e){}}
async function refreshStatus(){const x=await api('autoStatus');const r=resultOf(x)||{};byId('mAuto').textContent=r.enabled?'On':'Off';byId('mOnline').textContent=(r.running||0)+' / '+(r.target_online||0);byId('mOnlineLabel').textContent=gameMaxUser?'Online / Max '+gameMaxUser:'Online / Target';byId('mStore').textContent=String(r.store_running||0);const sx=await api('systemStatus');const s=resultOf(sx)||{};byId('robotUptimeHead').textContent='Runtime '+uptime(s.robot_uptime_seconds);const el=byId('mRobot');el.className='card good';el.querySelector('.v').textContent=Number(s.robot_cpu_percent||0).toFixed(1)+'% '+(s.robot_memory_mb||0)+'MB';el.querySelector('.k').textContent='Robot / '+(s.robot_threads||0)+' goroutines'}
async function refreshScheduler(){try{const x=await api('schedulerStatus');const s=resultOf(x)||{};byId('sMode').textContent=s.mode||'-';byId('sOnline').textContent=(s.online_start_rate||0)+'/s batch '+(s.online_batch_size||0);byId('sStore').textContent=(s.store_running||0)+'/'+(s.store_concurrent||0)+' p'+(s.store_probability_percent||0)+'%';byId('sScale').textContent='up '+(s.scale_up_batch||0)+' down '+(s.scale_down_batch||0);byId('sPressure').textContent='login '+(s.connecting||0)+' cpu '+Number(s.cpu_percent||0).toFixed(1)+'%';byId('sRelease').textContent='br '+(s.breaker_release_batch||0)+' port '+(s.port_down_release_batch||0);const op=s.recent_operation?(' | op '+s.recent_operation+' '+(s.recent_operation_state||'')+(s.recent_operation_summary?' '+s.recent_operation_summary:'')):'';byId('sReason').textContent=(s.reason||'-')+' | running '+(s.running||0)+'/'+(s.target_online||0)+' idle '+(s.idle||0)+' port '+(s.game_port_ready?'ready':'down')+' breaker '+(s.breaker_active?'on':'off')+' | actor i/a/o/r/b/rel '+(s.actor_idle||0)+'/'+(s.actor_assigned||0)+'/'+(s.actor_online||0)+'/'+(s.actor_running||0)+'/'+(s.actor_busy||0)+'/'+(s.actor_releasing||0)+op}catch(e){byId('sMode').textContent='error';byId('sReason').textContent=e.message}}
function uptime(sec){sec=Number(sec||0);const h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60),s=sec%60;return h?h+':'+String(m).padStart(2,'0')+':'+String(s).padStart(2,'0'):m+':'+String(s).padStart(2,'0')}
async function refreshRobots(){lastRobotsRefresh=Date.now();const x=await api('robotsStatus',{count:1000});const r=resultOf(x)||{};currentRows=r.robots||[];const tb=document.querySelector('#tbl tbody');tb.textContent='';tb.classList.remove('bulk-selected');const frag=document.createDocumentFragment();for(const a of currentRows){const uid=String(a.uid||'');const tr=document.createElement('tr');if(selected.has(uid))tr.className='sel';const cb=document.createElement('input');cb.type='checkbox';cb.checked=selected.has(uid);appendCell(tr,cb);appendCell(tr,uid);appendCell(tr,text(a.cid));appendCell(tr,text(a.name));const actor=document.createElement('span');const deleting=a.operation==='cleanup';actor.className='pill '+(deleting?'warn':(a.actor_attached?'ok':''));actor.textContent=deleting?'deleting':(a.actor_attached?('slot '+(a.actor_slot||'-')+' '+(a.actor_state||'')):'free');actor.title=deleting?'cleanup running':(a.actor_busy?('busy '+(a.actor_busy_kind||'')):'');appendCell(tr,actor);const rs=a.robot_state||{};const state=document.createElement('span');const bad=rs.actual_state==='error'||rs.actual_state==='disconnected'||rs.last_error;state.className='pill '+(bad?'bad':(rs.phase==='executing'?'warn':'ok'));state.textContent=(rs.actual_state||'-')+' -> '+(rs.desired_state||'-');state.title='db '+(a.db_state||'-')+' phase '+(rs.phase||'-')+(rs.last_error?' error '+rs.last_error:'')+(a.operation?' op '+a.operation:'');appendCell(tr,state);[a.level,jobGrowName(a.job,a.grow),villageDisplay(a),a.area,a.x,a.y,uptime(a.uptime_seconds)].forEach(v=>appendCell(tr,text(v)));const store=a.store_display_ack?'active':((a.store_created||a.robot_type==2||a.robot_type==3)?'pending':'');const span=document.createElement('span');if(store){span.className='pill '+(store==='active'?'ok':'warn');span.textContent=store}appendCell(tr,span);tr.onclick=e=>{tb.classList.remove('bulk-selected');if(e.target.tagName!=='INPUT')cb.checked=!cb.checked;cb.checked?selected.add(uid):selected.delete(uid);tr.className=selected.has(uid)?'sel':'';updateSelectedInfo()};frag.appendChild(tr)}tb.appendChild(frag);byId('listInfo').textContent=currentRows.length+' / '+(r.total||currentRows.length)+' robots, '+new Date().toLocaleTimeString();updateSelectedInfo()}
function appendCell(tr,v){const td=document.createElement('td');if(v instanceof Node)td.appendChild(v);else td.textContent=v;tr.appendChild(td)}function selectedPayload(){const u=[...selected].map(Number);return u.length?{uids:u}:{count:Math.max(1,Number(byId('actionCount').value||1))}}function updateSelectedInfo(){byId('selectedInfo').textContent='Selected '+selected.size;byId('checkAll').checked=currentRows.length>0&&currentRows.every(r=>selected.has(String(r.uid||'')))}
async function checkGame(){const x=await fetch('/api/game-port').then(r=>r.json());gameBlocked=!x.ok;gameMaxUser=Number(x.max_user_num||0);byId('mOnlineLabel').textContent=gameMaxUser?'Online / Max '+gameMaxUser:'Online / Target';byId('gameHead').textContent='Game: '+(x.ok?'open':'closed')+' '+(x.addr||'');const el=byId('mGame');el.className='card '+(x.ok?'good':'bad');el.querySelector('.v').textContent=x.ok?'Open':'Closed';el.title=(x.error||x.addr||'');applyKeyGate()}
function portOnly(addr){const s=text(addr);const i=s.lastIndexOf(':');return i>=0?s.slice(i+1):s}
function serviceView(label,name,open,addr){const port=portOnly(addr)||'-';const state=open?'open':'down';return {label,open,port,title:name+': '+state+' '+port}}
function renderServices(list){const el=byId('mMonitor');const allOpen=list.every(x=>x.open);el.className='card '+(allOpen?'good':'bad');el.querySelector('.v').innerHTML=list.map(x=>'<span class="svc" title="'+escapeHTML(x.title)+'"><span class="dot '+(x.open?'open':'closed')+'"></span>'+escapeHTML(x.label)+'</span>').join('');el.title=list.map(x=>x.title).join('\n')}
async function checkServices(){const monitor=await fetch('/api/monitor-service').then(r=>r.json()).catch(e=>({ok:false,error:e.message}));const relay=await fetch('/api/relay-service').then(r=>r.json()).catch(e=>({ok:false,error:e.message}));const market=await api('marketStatus').then(x=>resultOf(x)||{}).catch(e=>({services:{},error:e.message}));const services=market.services||{};const auction=services.auction||{},point=services.point||{};renderServices([serviceView('M','monitor',!!monitor.ok,monitor.addr),serviceView('A','auction',auction.status==='ready'&&!!auction.listening,auction.addr),serviceView('G','gold',point.status==='ready'&&!!point.listening,point.addr),serviceView('R','relay',!!relay.ok,relay.addr)])}
async function refreshDatabase(){try{const x=await api('databaseStatus');const r=resultOf(x)||{};dbBlocked=!r.ok;const el=byId('mDB');el.className='card '+(dbBlocked?'bad':'good');el.querySelector('.v').textContent=r.ok?'OK '+(r.latency_ms||0)+'ms':'Error';el.title=r.ok?(r.target||''):(r.error||'database unavailable');applyKeyGate()}catch(e){dbBlocked=true;applyKeyGate();const el=byId('mDB');el.className='card bad';el.querySelector('.v').textContent='Error';el.title=e.message}}
async function refreshKeypair(){try{const x=await api('keypairStatus');const r=resultOf(x)||{};keyBlocked=!(r.key_state==='default'||r.key_state==='user'||r.game_valid);const el=byId('mKey');el.className='card '+(keyBlocked?'bad':'good');el.querySelector('.v').textContent=keyStateText(r);applyKeyGate()}catch(e){keyBlocked=true;applyKeyGate();const el=byId('mKey');el.className='card bad';el.querySelector('.v').textContent='Error'}}
async function runAction(cmd){await guarded(actionName(cmd),async()=>{const x=await api(cmd,selectedPayload());setTimeout(refreshAll,1000);return x})}
function toggleAll(checked){const tb=document.querySelector('#tbl tbody');tb.classList.remove('bulk-selected');if(checked){currentRows.forEach(r=>selected.add(String(r.uid||'')))}else{selected.clear()}document.querySelectorAll('#tbl tbody tr').forEach(tr=>{const uid=tr.children[1]?tr.children[1].textContent:'';const on=selected.has(uid);tr.className=on?'sel':'';const cb=tr.querySelector('input[type=checkbox]');if(cb)cb.checked=on});updateSelectedInfo()}
function closeModal(){byId('modal').close()}function showModal(title,body,foot){byId('modalTitle').textContent=title;byId('modalBody').innerHTML=body;byId('modalFoot').innerHTML=foot||'<button onclick="closeModal()">Close</button>';byId('modal').showModal()}
function openOnlineDialog(){if(selected.size){runAction('robotsOnlineAsync');return}showModal('Online','<div class="formgrid"><label>Count</label><input id="onlineCount" type="number" min="1" max="1000" value="10"></div>','<button onclick="closeModal()">Cancel</button><button class="primary" onclick="submitOnline()">Online</button>')}async function submitOnline(){const c=Math.max(1,Number(byId('onlineCount').value||1));closeModal();await guarded('Online',async()=>api('robotsOnlineAsync',{count:c}))}
function openCleanupDialog(){const target=selected.size?selected.size+' selected robots':'all robot registry candidates';showModal('Cleanup','<p>Cleanup deletes robot registry/database rows for '+escapeHTML(target)+'. Normal shrink/logout should not use cleanup.</p>','<button onclick="closeModal()">Cancel</button><button class="danger" onclick="submitCleanup()">Cleanup</button>')}async function submitCleanup(){const p=selected.size?{uids:[...selected].map(Number),force:true}:{force:true};closeModal();await guarded('Cleanup',async()=>api('cleanupRobotsAsync',p))}
async function openAutoDialog(){await guarded('Read auto config',async()=>{const x=await api('robotConfigGet');const endpoint=await fetch('/api/game-endpoint').then(r=>r.json());if(!endpoint.ok)throw new Error(endpoint.error||'read game endpoint failed');const cfg=(resultOf(x)||{}).config||{},ports=endpoint.ports||{};showModal('Auto','<div class="formgrid"><label>Enabled</label><label><input id="autoEnabled" type="checkbox" '+(String(cfg.auto_actions)==='true'?'checked':'')+'> On</label><label>Target online</label><input id="autoTarget" type="number" min="1" max="1000" value="'+escapeHTML(cfg.auto_target_online_count||20)+'"><label>Fixed spawn</label><label><input id="spawnFixed" type="checkbox" '+(String(cfg.spawn_fixed)==='true'?'checked':'')+'> fixed town / birth point</label><label>Town</label><input id="spawnVillage" type="number" min="1" max="3" value="'+escapeHTML(cfg.spawn_village||3)+'"><label>Birth area</label><input id="spawnArea" type="number" min="0" max="999" value="'+escapeHTML(cfg.spawn_area||0)+'"><div class="muted" style="grid-column:1/-1">Ports</div><label>Game</label><input id="gamePort" type="number" min="1" max="65535" value="'+escapeHTML(ports.game||10011)+'"><label>Monitor</label><input id="monitorPort" type="number" min="1" max="65535" value="'+escapeHTML(ports.monitor||30303)+'"><label>Auction</label><input id="auctionPort" type="number" min="1" max="65535" value="'+escapeHTML(ports.auction||30803)+'"><label>Point</label><input id="pointPort" type="number" min="1" max="65535" value="'+escapeHTML(ports.point||30603)+'"><label>Relay</label><input id="relayPort" type="number" min="1" max="65535" value="'+escapeHTML(ports.relay||7200)+'"><div class="muted" style="grid-column:1/-1">Ports save to [Ports] in config.ini. Restart robot to apply them to robot connections and service checks.</div></div>','<button onclick="closeModal()">Cancel</button><button onclick="submitGamePort()">Save Ports</button><button onclick="submitAuto(false)">Save and pause</button><button class="primary" onclick="submitAuto(true)">Save and start</button>')})}
async function submitAuto(forceStart){const enabled=forceStart||byId('autoEnabled').checked;const updates={'auto.auto_target_online_count':String(byId('autoTarget').value||20),'auto.auto_actions':String(enabled),'spawn.spawn_fixed':String(byId('spawnFixed').checked),'spawn.spawn_village':String(byId('spawnVillage').value||3),'spawn.spawn_area':String(byId('spawnArea').value||0)};closeModal();await guarded('Auto',async()=>{const config=await api('robotConfigUpdate',{updates});const auto=await api(enabled?'autoStart':'autoStop');setTimeout(refreshAll,1000);return {config,auto}})}
async function submitGamePort(){const payload={game_port:Math.floor(Number(byId('gamePort').value||0)),monitor_port:Math.floor(Number(byId('monitorPort').value||0)),auction_port:Math.floor(Number(byId('auctionPort').value||0)),point_port:Math.floor(Number(byId('pointPort').value||0)),relay_port:Math.floor(Number(byId('relayPort').value||0))};if(Object.values(payload).some(p=>p<1||p>65535)){toast('Ports failed: enter 1-65535');return}closeModal();if(busy)return;setBusy(true);try{const x=await fetch('/api/game-endpoint',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)}).then(r=>r.json());writeLog(x);if(!x.ok)throw new Error(x.error||'save ports failed');toast(x.message||'saved; restart robot to apply');setTimeout(refreshAll,1000)}catch(e){writeLog({ok:false,error:e.message});toast('Ports failed: '+e.message)}finally{setBusy(false)}}
async function restartRobot(){if(!confirm('Restart robot process only? Game services will not be restarted.'))return;if(busy)return;setBusy(true);try{const x=await fetch('/api/restart-robot',{method:'POST'}).then(r=>r.json());writeLog(x);if(!x.ok)throw new Error(x.error||'restart failed');toast(x.message||'robot restart queued');setTimeout(()=>location.reload(),5000)}catch(e){writeLog({ok:false,error:e.message});toast('Restart failed: '+e.message);setBusy(false)}}
function keyStateText(r){if(r.key_state==='default'||r.using_default)return'Project Default Key';if(r.key_state==='user')return'User Key';if(r.key_state==='invalid')return'Invalid Key';if(r.key_state==='missing')return'Missing Key';return r.key_state||'-'}
function keyCompleteText(r){return r.game_valid?'Complete':'Incomplete'}
async function openKeyDialog(){await guarded('Key',async()=>{const x=await api('keypairStatus');const r=resultOf(x)||{};const fp=r.fingerprint?String(r.fingerprint).slice(0,16)+'...':'-';const body='<div class="formgrid"><label>Current key</label><div>'+escapeHTML(keyStateText(r))+'</div><label>Completeness</label><div>'+escapeHTML(keyCompleteText(r))+'</div><label>Game directory</label><div>'+escapeHTML(r.game_valid?'Complete':'Missing or invalid')+'</div><label>Config directory</label><div>'+escapeHTML(r.config_valid?'Complete':'Missing or invalid')+'</div><label>Bundled default</label><div>'+escapeHTML(r.default_valid?'Available':'Unavailable')+'</div><label>Fingerprint</label><div>'+escapeHTML(fp)+'</div><label>Game private</label><div class="muted">'+escapeHTML(r.game_private||'-')+'</div><label>Game public</label><div class="muted">'+escapeHTML(r.game_public||'-')+'</div></div>';showModal('RSA Key',body,'<button onclick="closeModal()">Close</button><button onclick="downloadDefaultKeypair()">Download Bundled Default Key</button><button class="primary" onclick="releaseDefaultKeypair()">Release Bundled Default Key</button>')})}
async function openMaxDialog(){await guarded('Read max user',async()=>{const x=await fetch('/api/max-user').then(r=>r.json());if(!x.ok)throw new Error(x.error||'read max user failed');showModal('Max Online','<div class="formgrid"><label>Max online</label><input id="maxUserNum" type="number" min="1" max="1000000" value="'+escapeHTML(x.max_user_num||1000)+'"><label>Config files</label><div>'+escapeHTML((x.files||[]).length)+' files</div><div class="muted" style="grid-column:1/-1">Updates max_user_num in all cfg files under the df_game_r cfg directory.</div></div>','<button onclick="closeModal()">Cancel</button><button class="primary" onclick="submitMaxUser()">Save</button>')})}
async function submitMaxUser(){const n=Math.floor(Number(byId('maxUserNum').value||0));if(!n||n<1){toast('Max failed: enter a positive number');return}closeModal();if(busy)return;setBusy(true);try{const x=await fetch('/api/max-user',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({max_user_num:n})}).then(r=>r.json());if(!x.ok)throw new Error(x.error||'update max user failed');gameMaxUser=n;byId('mOnlineLabel').textContent='Online / Max '+n;writeLog(x);toast(x.message||('updated '+((x.files||[]).length)+' files'));setTimeout(refreshAll,1000)}catch(e){writeLog({ok:false,error:e.message});toast('Max failed: '+e.message)}finally{setBusy(false)}}
function openScriptDialog(){showModal('Server Scripts','<div class="formgrid"><label>/root/run</label><div>Start game services</div><label>/root/stop</label><div>Stop game services</div></div>','<button onclick="closeModal()">Cancel</button><button class="primary" onclick="submitServerScript(&quot;run&quot;)">Run /root/run</button><button class="danger" onclick="submitServerScript(&quot;stop&quot;)">Run /root/stop</button>')}
async function submitServerScript(action){closeModal();if(busy)return;setBusy(true);try{const x=await fetch('/api/server-script',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action})}).then(r=>r.json());writeLog(x);if(!x.ok)throw new Error((x.error||'script failed')+(x.output?': '+x.output.slice(0,240):''));toast((x.script||action)+' ok');setTimeout(refreshAll,1000)}catch(e){writeLog({ok:false,error:e.message});toast('Script failed: '+e.message)}finally{setBusy(false)}}
async function openMarketDialog(){await guarded('Market',async()=>{const x=await api('marketStatus');showMarketDialog(resultOf(x)||{});return x})}
function showMarketDialog(s){const auto=s.auto||{},restock=s.restock||{};const markets=auto.markets||['auction','cera'];const hasAuction=markets.includes('auction');const hasGold=markets.includes('cera')||markets.includes('gold');const cycleSec=Math.max(1,Math.round(Number(auto.interval_ms||30000)/1000));const body='<div class="formgrid"><label>Status</label><div>'+escapeHTML(s.auto_running?'Running':'Stopped')+'</div><label>Cycle</label><div><input id="marketCycleSeconds" type="number" min="1" value="'+escapeHTML(cycleSec)+'" onchange="autoSaveMarketConfig()"> seconds</div><label>Concurrent</label><input id="marketConcurrent" type="number" min="1" max="256" value="'+escapeHTML(auto.max_concurrent||restock.max_concurrent||32)+'" onchange="autoSaveMarketConfig()"><label>Markets</label><div><label><input id="marketAuction" type="checkbox" '+(hasAuction?'checked':'')+' onchange="autoSaveMarketConfig()"> Auction</label> <label><input id="marketGold" type="checkbox" '+(hasGold?'checked':'')+' onchange="autoSaveMarketConfig()"> Gold</label></div></div>';const foot='<div style="display:grid;grid-template-columns:repeat(4,minmax(108px,1fr));gap:8px;width:100%"><button title="Start market auto loop" class="primary" onclick="submitMarketStart()">On</button><button title="Stop market auto loop" onclick="submitMarketStop()">Off</button><button title="Fill missing market listings" onclick="submitMarketRestock()">Restock</button><button title="Buy back player buyout listings" onclick="submitMarketCollect()">Collect</button><button class="danger" title="Delete robot market listings from database" onclick="submitMarketClearStock()">Clear Stock</button><button class="danger" title="Export PVF iteminfo.dat, delete robot listings, release dat, then restart auction and gold services" onclick="submitMarketItemInfo()">ItemInfo</button><button class="danger" title="Patch running auction memory for level and refine search limits" onclick="submitMarketMemoryPatch()">Memory Patch</button><button class="danger" title="Install df_game_r.js guard that blocks the dp2 auction search replace hook" onclick="submitMarketAuctionGuard()">Auction Guard</button></div>';showModal('Market',body,foot)}
function marketFormPayload(){const markets=[];if(byId('marketAuction').checked)markets.push('auction');if(byId('marketGold').checked)markets.push('cera');return {interval_ms:Math.max(1,Number(byId('marketCycleSeconds').value||30))*1000,max_concurrent:Math.max(1,Number(byId('marketConcurrent').value||32)),max_actions:0,continue_on_error:true,markets}}
let marketConfigTimer=null;function autoSaveMarketConfig(){clearTimeout(marketConfigTimer);marketConfigTimer=setTimeout(async()=>{try{await api('marketConfigUpdate',marketFormPayload());toast('Market config saved')}catch(e){toast('Market config failed: '+e.message)}},350)}
async function submitMarketConfig(){await api('marketConfigUpdate',marketFormPayload())}
async function submitMarketStart(){clearTimeout(marketConfigTimer);await submitMarketConfig();closeModal();await guarded('Market start',async()=>api('marketStart',{}))}
async function submitMarketStop(){closeModal();await guarded('Market stop',async()=>api('marketStop',{}))}
async function submitMarketCollect(){clearTimeout(marketConfigTimer);await submitMarketConfig();const c=Number(byId('marketConcurrent')?.value||32);closeModal();await guarded('Market recycle',async()=>api('marketCollectOnce',{market:'',max_concurrent:c,continue_on_error:true}))}
async function submitMarketRestock(){clearTimeout(marketConfigTimer);await submitMarketConfig();const c=Number(byId('marketConcurrent')?.value||32);closeModal();await guarded('Market restock',async()=>api('marketRestockOnce',{market:'',max_concurrent:c,continue_on_error:true}))}
async function submitMarketClearStock(){closeModal();await guarded('Market clear stock',async()=>api('marketClearSystemStock',{}))}
async function submitMarketItemInfo(){closeModal();await guarded('Market iteminfo',async()=>api('marketSyncItemInfo',{}))}
async function submitMarketAuctionGuard(){closeModal();await guarded('Auction guard',async()=>{const x=await api('marketInstallAuctionGuard',{});const r=resultOf(x)||{};toast(r.changed?'Auction guard installed, restart game':'Auction guard already installed');return x})}
async function submitMarketMemoryPatch(){closeModal();await guarded('Auction memory patch',async()=>{const x=await api('marketPatchAuctionMemory',{});const r=resultOf(x)||{};const ok=(r.entries||[]).filter(e=>e.ok).length;toast('Auction memory patch '+ok+'/'+((r.entries||[]).length||0)+' pid '+(r.pid||'-'));return x})}
async function openPartyCompatDialog(){await guarded('Party',async()=>{const x=await fetch('/api/party-compat').then(r=>r.json());if(!x.ok)throw new Error(x.error||'status failed');const s=x.result||{};const body='<div class="formgrid"><label>Status</label><div>'+escapeHTML(s.enabled?'Running':'Stopped')+'</div><label>Game process</label><div>PID '+escapeHTML(s.pid||'-')+' / port '+escapeHTML(s.port||'-')+'</div><label>Account start</label><input id="partyCompatStart" type="number" min="1" max="4294967295" value="'+escapeHTML(s.account_start||17000000)+'"><label>Account end</label><input id="partyCompatEnd" type="number" min="1" max="4294967295" value="'+escapeHTML(s.account_end||17001000)+'"></div>';showModal('Party',body,'<button onclick="submitPartyCompat(\'off\')">Off</button><button class="primary" onclick="submitPartyCompat(\'on\')">On</button>');return x})}
async function submitPartyCompat(action){const account_start=Math.floor(Number(byId('partyCompatStart').value||0)),account_end=Math.floor(Number(byId('partyCompatEnd').value||0));if(!account_start||account_end<=account_start){toast('Party patch failed: invalid account range');return}closeModal();await guarded('Party patch '+action,async()=>{const x=await fetch('/api/party-compat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action,account_start,account_end})}).then(r=>r.json());if(!x.ok)throw new Error(x.error||'update failed');return x})}
async function releaseDefaultKeypair(){closeModal();await guarded('Release Bundled Default Key',async()=>api('keypairReleaseDefault',{}))}
function downloadDefaultKeypair(){window.location='/api/keypair-download'}
function toggleAutoRefresh(){if(autoRefreshTimer){clearInterval(autoRefreshTimer);autoRefreshTimer=null}const el=byId('autoRefreshInterval');const v=el?.value;if(v)localStorage.setItem('tw_auto_refresh_interval',v);if(v&&v!=='off')autoRefreshTimer=setInterval(refreshQuiet,Number(v))}
function restoreAutoRefresh(){const saved=localStorage.getItem('tw_auto_refresh_interval');const el=byId('autoRefreshInterval');if(saved&&el&&[...el.options].some(o=>o.value===saved))el.value=saved;toggleAutoRefresh()}
refreshAll();restoreAutoRefresh();
</script></body></html>`))
